select 
from downstream_push_record


        and (push_id like #{keywordLike}
        or trace_id like #{keywordLike}
        or task_id like #{keywordLike}
        or document_id like #{keywordLike}
        or idempotent_key like #{keywordLike}
        or response_message like #{keywordLike})


        and target_system = #{query.targetSystem}


        and service_code = #{query.serviceCode}


        and status = #{query.status}


        and push_method = #{query.pushMethod}


order by pushed_at desc, updated_at desc

